#!/bin/bash
TARGET_DIR="public/sounds"
mkdir -p "$TARGET_DIR"
BASE64_STR=""

echo "$BASE64_STR" | base64 -D > "$TARGET_DIR/success.mp3"
echo "$BASE64_STR" | base64 -D > "$TARGET_DIR/error.mp3"
echo "$BASE64_STR" | base64 -D > "$TARGET_DIR/approval.mp3"
echo "$BASE64_STR" | base64 -D > "$TARGET_DIR/lead.mp3"
echo "$BASE64_STR" | base64 -D > "$TARGET_DIR/notification.mp3"
echo "Binary dummy sounds written."
